package timer

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/timer"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type TimerProxy struct {
	timer.UnimplementedTimerServer
	client timer.TimerClient
}

func init() {
	proxyutil.Register(&timer.Timer_ServiceDesc, NewTimerProxy)
}
func NewTimerProxy(cc grpc.ClientConnInterface) timer.TimerServer {
	return &TimerProxy{client: timer.NewTimerClient(cc)}
}
func (p *TimerProxy) Wait(ctx context.Context, in *timer.TimerMessage) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[timer.TimerMessage, emptypb.Empty](p.client.Wait)(ctx, in)
}
